import React, { useRef, useState } from 'react';

const TOOLS = [
  { cmd: 'bold', label: 'B', style: { fontWeight: 700 } },
  { cmd: 'italic', label: 'I', style: { fontStyle: 'italic' } },
  { cmd: 'underline', label: 'U', style: { textDecoration: 'underline' } },
  { cmd: 'insertUnorderedList', label: '• List', style: {} },
];

export default function RichTextEditor() {
  const ref = useRef(null);
  const [html, setHtml] = useState('');

  const exec = (cmd) => {
    document.execCommand(cmd, false);
    if (ref.current) ref.current.focus();
  };

  return (
    <div style={{ maxWidth: 420 }}>
      <div style={{ display: 'flex', gap: 4, marginBottom: 8 }}>
        {TOOLS.map((t) => (
          <button
            key={t.cmd}
            onMouseDown={(e) => {
              e.preventDefault();
              exec(t.cmd);
            }}
            style={{ ...t.style, padding: '6px 10px', cursor: 'pointer', border: '1px solid #cbd5e1', borderRadius: 6, background: '#fff' }}
          >
            {t.label}
          </button>
        ))}
      </div>

      <div
        ref={ref}
        contentEditable
        suppressContentEditableWarning
        onInput={() => setHtml(ref.current.innerHTML)}
        style={{ minHeight: 120, border: '1px solid #cbd5e1', borderRadius: 8, padding: 12, lineHeight: 1.5, outline: 'none' }}
      >
        Select some text and use the toolbar.
      </div>

      <details style={{ marginTop: 12 }}>
        <summary style={{ cursor: 'pointer', color: '#64748b' }}>HTML output</summary>
        <pre style={{ background: '#f1f5f9', padding: 10, borderRadius: 6, whiteSpace: 'pre-wrap' }}>{html}</pre>
      </details>
    </div>
  );
}

