import { Component, ViewChild, ElementRef } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Tool { cmd: string; label: string; cls: string; }

@Component({
  selector: 'app-rich-text-editor',
  template: `
    <div style="max-width: 420px;">
      <div style="display: flex; gap: 4px; margin-bottom: 8px;">
        <button
          *ngFor="let t of tools"
          (mousedown)="$event.preventDefault(); exec(t.cmd)"
          [class]="t.cls"
          style="padding: 6px 10px; cursor: pointer; border: 1px solid #cbd5e1; border-radius: 6px; background: #fff;"
        >{{ t.label }}</button>
      </div>

      <div
        #editor
        contenteditable="true"
        (input)="html = editor.innerHTML"
        style="min-height: 120px; border: 1px solid #cbd5e1; border-radius: 8px; padding: 12px; line-height: 1.5; outline: none;"
      >Select some text and use the toolbar.</div>

      <details style="margin-top: 12px;">
        <summary style="cursor: pointer; color: #64748b;">HTML output</summary>
        <pre style="background: #f1f5f9; padding: 10px; border-radius: 6px; white-space: pre-wrap;">{{ html }}</pre>
      </details>
    </div>
  `,
  styles: [`
    .b { font-weight: 700; }
    .i { font-style: italic; }
    .u { text-decoration: underline; }
  `],
})
export class RichTextEditorComponent {
  @ViewChild('editor') editor!: ElementRef<HTMLElement>;
  html = '';
  tools: Tool[] = [
    { cmd: 'bold', label: 'B', cls: 'b' },
    { cmd: 'italic', label: 'I', cls: 'i' },
    { cmd: 'underline', label: 'U', cls: 'u' },
    { cmd: 'insertUnorderedList', label: '• List', cls: '' },
  ];

  exec(cmd: string): void {
    document.execCommand(cmd, false);
    this.editor.nativeElement.focus();
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Rich Text Editor Demo</h1>
      <app-rich-text-editor></app-rich-text-editor>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, RichTextEditorComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
